var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"고민 상담이요?","JPN":"お悩み相談ですか？","ENG":"You want me to do counseling for customers?","TWN":"心理諮商嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"응, 가게를 찾아오는 손님들 중엔 마음의 위로가 필요해서 오는 사람들도 있거든.","JPN":"ええ、店に訪れるお客さんの中には、心の癒しを求めて来る人もいるのよ。","ENG":"Yes. Some of our customers come here, seeking comfort.","TWN":"對，來到店裡的客人中，有些是因為想要得到心靈的慰藉。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"바텐딩 기술도 물론 중요하지만, 우리 가게에서 제일 우선시해야 하는 건 손님의 고민을 잘 들어주는 거야.","JPN":"バーテンディングの技術ももちろん大事だけど、\\nうちの店で一番優先すべき仕事はお客さんの悩みをよく聞いてあげることよ。","ENG":"Bartending skills are important, but in my bar, they're not as important as listening skills.","TWN":"調酒技術固然重要，但在我們店裡，最重要的是聆聽客人的煩惱。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제가… 그런 걸 할 수 있을까요?","JPN":"私に……そんなことができるのでしょうか？","ENG":"But... I don't know if I can give good advice.","TWN":"我…做得到嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 물론이지.","JPN":"ふふっ、もちろん。","ENG":"Hah hah. Yes, you can.","TWN":"呵呵，那當然囉！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"상담이라고 거창하게 말하긴 했지만, 반드시 정답을 제시해 줄 필요는 없어.","JPN":"相談なんておおげさに言ってしまったけれど、\\n必ずしも正解を提示する必要はないわ。","ENG":"Even though I said counseling, you don't have to give them solutions.","TWN":"諮商聽起來好像很專業，但其實不是一定要給出什麼答案來。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 사람의 마음에 공감해준다는 제스처 자체가 중요한 거니까 말이야.","JPN":"その人の心に共感しているというジェスチャー自体が大事なんだから。","ENG":"They just want you to listen and emphasize with them, that's all.","TWN":"重點透過肢體或表情，來表達你是同理對方的。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네! 그 정도라면 저에게 맡겨주세요!","JPN":"はい！　それくらいなら私に任せてください！","ENG":"Sure, I think I can do that.","TWN":"好！這個我應該做得到！"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"으흑… 흐윽… 나쁜 놈! 내가 얼마나 잘 해줬는데…","JPN":"うふっ……ううっ……最低な男！　私がどれだけよくしてあげたか……","ENG":"*Sob* That jerk! I treated him like a prince!","TWN":"嗚嗚…嗚嗚…該死的渣男！虧我對你那麼好…"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"자 자, 진정하고 한잔하세요.","JPN":"まあまあ、落ち着いて一杯飲みましょう。","ENG":"Come on, stop crying and drink this.","TWN":"來吧，喝一杯，平復一下心情～"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"너무 미운데… 나쁜 놈인데… 자꾸 생각나는 거 있죠?","JPN":"憎いし……悪い男なのに……どうしても思い出してしまうんです。","ENG":"I hate him so much, and yet, I can't stop thinking about him.","TWN":"他那麼過分…那麼可惡…為什麼我還是一直會想起他？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음, 많이 힘드시겠어요.","JPN":"それは本当に辛いですね。","ENG":"Mm, that must be hard.","TWN":"我懂我懂，很痛苦對吧？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(으아, 실연이라니… 저에겐 공감하기 어려운 주제네요.)","JPN":"(うわあ、失恋ですか……私には共感しにくいテーマですね。)","ENG":"(Err, relationship problems... I don't know how to react...)","TWN":"(哎呀，這次是失戀…這個話題對我來說有點困難。)"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(그래도 어떻게든 되겠죠! 중요한 건 제스처니까요!)","JPN":"(でもなんとかなるでしょう！　大事なのはジェスチャーですから！)","ENG":"(But I'll try! What matters is that I listen!)","TWN":"(不過應該OK吧？反正重點是肢體跟表情！)"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"흑… 잊어버리고 싶은데… 너무 괴롭네요… 저는 어떻게 해야 좋을까요?","JPN":"ぐすん……忘れたいのに……辛すぎる……私はどうすればいいですか？","ENG":"*Sniffle* I want to forget him, but I can't... What do I do?","TWN":"嗚嗚…我好想忘了他…真的好痛苦…我該怎麼辦？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>네 이웃을 네 몸과 같이 사랑하라</color>는 말 들어보셨나요?","JPN":"<color=#ffd34c>「あなたの隣人をあなた自身のように愛せよ」</color>という言葉を知っていますか？","ENG":"Have you heard of the phrase, \\"<color=#ffd34c>Love thy neighbor as thyself</color>?\\"","TWN":"<color=#ffd34c>要愛鄰舍如同自己</color>，這句話你聽過嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"네……? 갑자기 그게 무슨……?","JPN":"はい……？　それはどういう意味ですか……？","ENG":"Huh? What does that have to do with me?","TWN":"什麼……？這什麼意思……？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};